import React, { useState } from "react";
import { Calendar } from "primereact/calendar";
import { MultiSelect } from "primereact/multiselect";
import axios from "axios";
import moment from "moment";
import { Button } from "primereact/button";
import { BlockUI } from "primereact/blockui";
import { Divider } from "primereact/divider";
import { useTheme } from "../context/ThemeContext";

export default function Upload() {
    const { isDarkMode } = useTheme();
	const [start_date, setStart_Date] = useState();
	const [end_date, setEnd_Date] = useState();

	const [Selected_lines_states, setSelected_lines_states] = useState();
	const [blocked, setBlocked] = useState(false);
	const [loading_show, setloading_show] = useState(false);

	const values = [
		"Frequency",
		"Voltage",
		"Lines",
		"ICT",
		"Demand",
		"Generator",
		"Thermal Generator",
		"ISGS",
		"Exchange",
	];

	const uploaddata = () => {
		if (Selected_lines_states && start_date && end_date) {
            setloading_show(true);
			for (var i = 0; i < Selected_lines_states.length; i++) {
				if (Selected_lines_states[i] === "Voltage") {
					axios
						.post(
							"/VoltageFileInsert?startDate=" +
								moment(start_date).format("YYYY-MM-DD") +
								"&endDate=" +
								moment(end_date).format("YYYY-MM-DD")
						)
						.then((response) => {
							alert("Voltage data inserted for " + response.data["dates"]);
						})
						.catch((error) => {});
				} else if (Selected_lines_states[i] === "Lines") {
					axios
						.post(
							"/LinesFileInsert?startDate=" +
								moment(start_date).format("YYYY-MM-DD") +
								"&endDate=" +
								moment(end_date).format("YYYY-MM-DD"),
							"Lines MW"
						)
						.then((response) => {})
						.catch((error) => {});

					axios
						.post(
							"/MVARFileInsert?startDate=" +
								moment(start_date).format("YYYY-MM-DD") +
								"&endDate=" +
								moment(end_date).format("YYYY-MM-DD")
						)
						.then((response) => {
							alert("Lines data inserted for " + response.data);
						})
						.catch((error) => {});
				} else if (Selected_lines_states[i] === "ICT") {
					axios
						.post(
							"/ICTFileInsert?startDate=" +
								moment(start_date).format("YYYY-MM-DD") +
								"&endDate=" +
								moment(end_date).format("YYYY-MM-DD"),
							{}
						)
						.then((response) => {
							alert("ICT data inserted for " + response.data);
						})
						.catch((error) => {});
				} else if (Selected_lines_states[i] === "Demand") {
					axios
						.post(
							"/DemandFileInsert?startDate=" +
								moment(start_date).format("YYYY-MM-DD") +
								"&endDate=" +
								moment(end_date).format("YYYY-MM-DD")
						)
						.then((response) => {
							alert("Demand data inserted for " + response.data);
						})
						.catch((error) => {});
				} else if (Selected_lines_states[i] === "Generator") {
					axios
						.post(
							"/GeneratorFileInsert?startDate=" +
								moment(start_date).format("YYYY-MM-DD") +
								"&endDate=" +
								moment(end_date).format("YYYY-MM-DD")
						)
						.then((response) => {
							alert("Generator data inserted for " + response.data);
						})
						.catch((error) => {});
				} else if (Selected_lines_states[i] === "Thermal Generator") {
					axios
						.post(
							"/ThGeneratorFileInsert?startDate=" +
								moment(start_date).format("YYYY-MM-DD") +
								"&endDate=" +
								moment(end_date).format("YYYY-MM-DD")
						)
						.then((response) => {
							alert("Thermal Generator data inserted for " + response.data);
						})
						.catch((error) => {});
				} else if (Selected_lines_states[i] === "ISGS") {
					axios
						.post(
							"/ISGSFileInsert?startDate=" +
								moment(start_date).format("YYYY-MM-DD") +
								"&endDate=" +
								moment(end_date).format("YYYY-MM-DD")
						)
						.then((response) => {
							alert("Frequency data inserted for " + response.data);
						})
						.catch((error) => {});
				} else if (Selected_lines_states[i] === "Frequency") {
					axios
						.post(
							"/FrequencyFileInsert?startDate=" +
								moment(start_date).format("YYYY-MM-DD") +
								"&endDate=" +
								moment(end_date).format("YYYY-MM-DD")
						)
						.then((response) => {
							alert("Frequency data inserted for " + response.data);
						})
						.catch((error) => {});
				} else if (Selected_lines_states[i] === "Exchange") {
					axios
						.post(
							"/ExchangeFileInsert?startDate=" +
								moment(start_date).format("YYYY-MM-DD") +
								"&endDate=" +
								moment(end_date).format("YYYY-MM-DD")
						)
						.then((response) => {
							alert("Exchange data inserted for " + response.data);
						})
						.catch((error) => {});
				}
			}
			setBlocked(false);
			setloading_show(false);
		}
	};

	return (
		<div className={`page-container animate-fade-in ${isDarkMode ? "dark-theme" : "light-theme"}`}>
			<div hidden={!loading_show}>
				<div className="loader">
					<div className="spinner"></div>
				</div>
			</div>

			<BlockUI blocked={blocked} fullScreen />
			
            <div className="page-header mb-8">
                <div className="flex align-items-center gap-4">
                    <div className="status-orb pulse red"></div>
                    <div>
                        <h1 className="text-4xl font-extrabold tracking-tighter">
                            DATA <span className="text-primary">INGESTION</span>
                        </h1>
                        <p className="text-muted text-sm font-medium uppercase tracking-widest text-primary font-bold">Synchronize Grid Telemetry to Core Storage</p>
                    </div>
                </div>
            </div>

            <div className="flex justify-content-center">
                <div className="glass-panel p-6 w-full md:w-8 lg:w-6 shadow-2xl animate-scale-up">
                    <div className="flex flex-column gap-6">
                        <div className="grid">
                            <div className="col-12 md:col-6">
                                <label className="block mb-3 font-bold text-accent uppercase text-xs tracking-widest opacity-70">Temporal Start (Origin)</label>
                                <Calendar
                                    className="w-full premium-calendar"
                                    showIcon
                                    placeholder="Select Start Date"
                                    dateFormat="dd-mm-yy"
                                    value={start_date}
                                    onChange={(e) => setStart_Date(e.value)}
                                    monthNavigator
                                    yearNavigator
                                    yearRange="2015:2030"
                                    showButtonBar
                                />
                            </div>
                            <div className="col-12 md:col-6">
                                <label className="block mb-3 font-bold text-accent uppercase text-xs tracking-widest opacity-70">Temporal End (Target)</label>
                                <Calendar
                                    className="w-full premium-calendar"
                                    showIcon
                                    placeholder="Select End Date"
                                    dateFormat="dd-mm-yy"
                                    value={end_date}
                                    onChange={(e) => setEnd_Date(e.value)}
                                    monthNavigator
                                    yearNavigator
                                    yearRange="2015:2030"
                                    showButtonBar
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block mb-3 font-bold text-accent uppercase text-xs tracking-widest opacity-70">Metric Stream Discovery</label>
                            <MultiSelect
                                className="w-full premium-multiselect"
                                display="chip"
                                placeholder="Choose Grid Data Streams"
                                value={Selected_lines_states}
                                options={values}
                                onChange={(e) => setSelected_lines_states(e.value)}
                                filter
                            />
                        </div>

                        <Divider className="my-4 opacity-50" />

                        <div className="flex justify-content-center">
                            <Button
                                icon="pi pi-cloud-upload"
                                className="ultimate-action-btn px-8 py-4 w-full md:w-auto"
                                label="EXECUTE DATA SYNCHRONIZATION"
                                onClick={() => {
                                    uploaddata();
                                }}
                            />
                        </div>
                    </div>
                </div>
            </div>

            <div className="mt-8 text-center animate-fade-in" style={{ animationDelay: '0.4s' }}>
                <div className="inline-flex align-items-center gap-2 p-3 glass-effect border-round-3xl">
                    <i className="pi pi-info-circle text-primary"></i>
                    <span className="text-xs font-semibold opacity-70 uppercase tracking-widest">System idle: Awaiting ingestion parameters</span>
                </div>
            </div>
		</div>
	);
}
